import {
  CREATE2_EVM_PREFIX,
  ERA_VM_BYTECODE_FLAG,
  EVM_BYTECODE_FLAG
} from "../Constants.sol";
import {
  BytecodeError,
  MalformedBytecode,
  Overflow
} from "../SystemContractErrors.sol";
import { EfficientCall } from "./EfficientCall.sol";
import { RLPEncoder } from "./RLPEncoder.sol";

