contracts/OltinPaymaster.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IPaymaster, ExecutionResult, PAYMASTER_VALIDATION_SUCCESS_MAGIC} from "@matterlabs/zksync-contracts/contracts/system-contracts/interfaces/IPaymaster.sol";
import {IPaymasterFlow} from "@matterlabs/zksync-contracts/contracts/system-contracts/interfaces/IPaymasterFlow.sol";
import {Transaction} from "@matterlabs/zksync-contracts/contracts/system-contracts/libraries/TransactionHelper.sol";
import {BOOTLOADER_FORMAL_ADDRESS} from "@matterlabs/zksync-contracts/contracts/system-contracts/Constants.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title OltinPaymaster
 * @notice Paymaster that accepts OLTIN tokens as fee payment
 * @dev Users pay transfer fees in OLTIN, Paymaster covers ETH gas
 * 
 * Flow:
 * 1. User approves Paymaster to spend OLTIN
 * 2. User sends tx with paymasterParams
 * 3. Paymaster takes OLTIN fee, pays ETH gas
 * 4. User gets gasless transaction
 */
contract OltinPaymaster is IPaymaster, Ownable {

    IERC20 public immutable oltinToken;

    /// @notice Fee in basis points (100 = 1%, 50 = 0.5%)
    uint256 public feeBasisPoints = 50;

    /// @notice Minimum fee in OLTIN (wei, 18 decimals)
    uint256 public minFeeWei = 0.0001 ether; // 0.0001 gram

    /// @notice Accumulated fees
    uint256 public totalFeesCollected;

    event FeePaid(
        address indexed user,
        uint256 oltinFee,
        bytes32 indexed txHash
    );
    event FeesWithdrawn(address indexed to, uint256 amount);
    event FeeConfigUpdated(uint256 basisPoints, uint256 minFee);

    modifier onlyBootloader() {
        require(
            msg.sender == BOOTLOADER_FORMAL_ADDRESS,
            "Paymaster: not bootloader"
        );
        _;
    }

    constructor(address _oltinToken) Ownable(msg.sender) {
        require(_oltinToken != address(0), "Invalid token");
        oltinToken = IERC20(_oltinToken);
    }

    /**
     * @notice Validate transaction and collect OLTIN fee
     */
    function validateAndPayForPaymasterTransaction(
        bytes32,
        bytes32,
        Transaction calldata _transaction
    )
        external
        payable
        onlyBootloader
        returns (bytes4 magic, bytes memory context)
    {
        magic = PAYMASTER_VALIDATION_SUCCESS_MAGIC;

        // Decode paymaster input to get approval-based flow params
        require(
            _transaction.paymasterInput.length >= 4,
            "Paymaster: invalid input"
        );

        bytes4 paymasterInputSelector = bytes4(
            _transaction.paymasterInput[0:4]
        );

        require(
            paymasterInputSelector == IPaymasterFlow.approvalBased.selector,
            "Paymaster: unsupported flow"
        );

        // Decode: token, minAllowance, innerInput
        (address token, uint256 minAllowance, ) = abi.decode(
            _transaction.paymasterInput[4:],
            (address, uint256, bytes)
        );

        require(token == address(oltinToken), "Paymaster: wrong token");

        address user = address(uint160(_transaction.from));

        // Calculate fee: basis points of minAllowance or minFee
        uint256 fee = (minAllowance * feeBasisPoints) / 10000;
        if (fee < minFeeWei) {
            fee = minFeeWei;
        }

        // Verify allowance
        uint256 allowance = oltinToken.allowance(user, address(this));
        require(allowance >= fee, "Paymaster: allowance too low");

        // Collect OLTIN fee
        bool success = oltinToken.transferFrom(user, address(this), fee);
        require(success, "Paymaster: fee transfer failed");

        totalFeesCollected += fee;

        // Pay ETH to bootloader for gas
        uint256 requiredETH = _transaction.gasLimit * _transaction.maxFeePerGas;
        (bool ethSent, ) = payable(BOOTLOADER_FORMAL_ADDRESS).call{
            value: requiredETH
        }("");
        require(ethSent, "Paymaster: ETH payment failed");

        context = abi.encode(user, fee);
    }

    /**
     * @notice Post-transaction callback (refunds, logging)
     */
    function postTransaction(
        bytes calldata _context,
        Transaction calldata,
        bytes32 _txHash,
        bytes32,
        ExecutionResult,
        uint256
    ) external payable override onlyBootloader {
        (address user, uint256 fee) = abi.decode(_context, (address, uint256));
        emit FeePaid(user, fee, _txHash);
    }

    // ============ Admin ============

    function setFeeConfig(
        uint256 _basisPoints, 
        uint256 _minFeeWei
    ) external onlyOwner {
        require(_basisPoints <= 500, "Fee max 5%");
        feeBasisPoints = _basisPoints;
        minFeeWei = _minFeeWei;
        emit FeeConfigUpdated(_basisPoints, _minFeeWei);
    }

    function withdrawFees(address _to) external onlyOwner {
        uint256 amount = totalFeesCollected;
        require(amount > 0, "No fees");
        totalFeesCollected = 0;
        oltinToken.transfer(_to, amount);
        emit FeesWithdrawn(_to, amount);
    }

    function withdrawETH(address payable _to) external onlyOwner {
        (bool success, ) = _to.call{value: address(this).balance}("");
        require(success, "ETH withdraw failed");
    }

    /// @notice Deposit ETH for gas coverage
    receive() external payable {}
}

contracts/OltinToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title OltinToken
 * @dev Gold-backed ERC20 token for OltinChain platform
 * 1 OLTIN = 1 gram of physical gold
 * 
 * Features:
 * - Role-based access control (MINTER, BURNER, PAUSER)
 * - Pausable transfers for emergency
 * - Event logging with orderId for audit trail
 */
contract OltinToken is ERC20, ERC20Burnable, AccessControl, Pausable {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");

    /// @notice Emitted when tokens are minted (user buys gold)
    event Minted(
        address indexed to,
        uint256 amount,
        string orderId,
        uint256 timestamp
    );

    /// @notice Emitted when tokens are burned (user sells gold)
    event Burned(
        address indexed from,
        uint256 amount,
        string orderId,
        uint256 timestamp
    );

    /**
     * @dev Constructor grants all roles to deployer
     */
    constructor() ERC20("Oltin Gold Token", "OLTIN") {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(BURNER_ROLE, msg.sender);
        _grantRole(PAUSER_ROLE, msg.sender);
    }

    /**
     * @notice Mint new tokens when user purchases gold
     * @param to Recipient address
     * @param amount Amount in wei (18 decimals)
     * @param orderId Platform order ID for audit trail
     */
    function mint(
        address to,
        uint256 amount,
        string calldata orderId
    ) external onlyRole(MINTER_ROLE) whenNotPaused {
        require(to != address(0), "OltinToken: mint to zero address");
        require(amount > 0, "OltinToken: amount must be positive");
        require(bytes(orderId).length > 0, "OltinToken: orderId required");

        _mint(to, amount);
        emit Minted(to, amount, orderId, block.timestamp);
    }

    /**
     * @notice Burn tokens when user sells gold
     * @param from Token holder address
     * @param amount Amount in wei (18 decimals)
     * @param orderId Platform order ID for audit trail
     */
    function burn(
        address from,
        uint256 amount,
        string calldata orderId
    ) external onlyRole(BURNER_ROLE) whenNotPaused {
        require(from != address(0), "OltinToken: burn from zero address");
        require(amount > 0, "OltinToken: amount must be positive");
        require(bytes(orderId).length > 0, "OltinToken: orderId required");
        require(balanceOf(from) >= amount, "OltinToken: insufficient balance");

        _burn(from, amount);
        emit Burned(from, amount, orderId, block.timestamp);
    }

    /**
     * @notice Pause all token transfers (emergency)
     */
    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    /**
     * @notice Unpause token transfers
     */
    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    /**
     * @dev Override to add pause check to transfers
     */
    function _update(
        address from,
        address to,
        uint256 value
    ) internal override whenNotPaused {
        super._update(from, to, value);
    }

    /**
     * @notice Returns 18 decimals for fractional gram support
     * @dev 0.000000000000000001 OLTIN = 1 attogram
     */
    function decimals() public pure override returns (uint8) {
        return 18;
    }
}

contracts/OltinTokenV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title OltinToken V2
 * @dev Gold-backed ERC20 with admin transfer (gasless for users)
 */
contract OltinTokenV2 is ERC20, ERC20Burnable, AccessControl, Pausable {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");

    /// @notice Transfer fee in basis points (50 = 0.5%)
    uint256 public transferFeeBps = 50;

    /// @notice Fee collector address
    address public feeCollector;

    event Minted(address indexed to, uint256 amount, string orderId, uint256 timestamp);
    event Burned(address indexed from, uint256 amount, string orderId, uint256 timestamp);
    event AdminTransfer(
        address indexed from, 
        address indexed to, 
        uint256 amount, 
        uint256 fee,
        string transferId
    );
    event FeeConfigUpdated(uint256 feeBps, address collector);

    constructor(address _feeCollector) ERC20("Oltin Gold Token", "OLTIN") {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(BURNER_ROLE, msg.sender);
        _grantRole(PAUSER_ROLE, msg.sender);
        feeCollector = _feeCollector;
    }

    /**
     * @notice Mint tokens (user buys gold)
     */
    function mint(
        address to,
        uint256 amount,
        string calldata orderId
    ) external onlyRole(MINTER_ROLE) whenNotPaused {
        require(to != address(0), "Zero address");
        require(amount > 0, "Zero amount");
        _mint(to, amount);
        emit Minted(to, amount, orderId, block.timestamp);
    }

    /**
     * @notice Burn tokens (user sells gold)
     */
    function burn(
        address from,
        uint256 amount,
        string calldata orderId
    ) external onlyRole(BURNER_ROLE) whenNotPaused {
        require(from != address(0), "Zero address");
        require(amount > 0, "Zero amount");
        require(balanceOf(from) >= amount, "Insufficient balance");
        _burn(from, amount);
        emit Burned(from, amount, orderId, block.timestamp);
    }

    /**
     * @notice Admin transfer (gasless for users)
     * @dev Only minter can call. Fee deducted from amount.
     * @param from Sender address
     * @param to Recipient address  
     * @param amount Total amount (fee will be deducted)
     * @param transferId Unique transfer ID for audit
     */
    function adminTransfer(
        address from,
        address to,
        uint256 amount,
        string calldata transferId
    ) external onlyRole(MINTER_ROLE) whenNotPaused {
        require(from != address(0) && to != address(0), "Zero address");
        require(amount > 0, "Zero amount");
        require(balanceOf(from) >= amount, "Insufficient balance");
        require(bytes(transferId).length > 0, "Transfer ID required");

        // Calculate fee
        uint256 fee = (amount * transferFeeBps) / 10000;
        uint256 netAmount = amount - fee;

        // Transfer: from -> to (net amount)
        _update(from, to, netAmount);

        // Transfer: from -> feeCollector (fee)
        if (fee > 0 && feeCollector != address(0)) {
            _update(from, feeCollector, fee);
        }

        emit AdminTransfer(from, to, netAmount, fee, transferId);
    }

    /**
     * @notice Update fee configuration
     */
    function setFeeConfig(
        uint256 _feeBps,
        address _collector
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_feeBps <= 500, "Fee max 5%");
        transferFeeBps = _feeBps;
        feeCollector = _collector;
        emit FeeConfigUpdated(_feeBps, _collector);
    }

    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    function _update(
        address from,
        address to,
        uint256 value
    ) internal override whenNotPaused {
        super._update(from, to, value);
    }

    function decimals() public pure override returns (uint8) {
        return 18;
    }
}

